const htmlStr = input.html;
if (typeof htmlStr !== "string" || !htmlStr) throw new Error("Missing HTML");

// ---- extract antiforgery token ----
const m = htmlStr.match(/name="__RequestVerificationToken"[^>]*value="([^"]+)"/i);
if (!m) throw new Error("Token not found");

const token = m[1];

// ---- compute stable 30-min window aligned to :00 / :30 (UTC) ----
const now = new Date();

// floor to last :00 or :30 (UTC)
const end = new Date(now);
end.setUTCSeconds(0, 0);
const mins = end.getUTCMinutes();
end.setUTCMinutes(mins < 30 ? 0 : 30, 0, 0);

// start = end - 30 minutes
const start = new Date(end.getTime() - 30 * 60 * 1000);

return [{
  token,
  windowStart: start.toISOString(),
  windowEnd: end.toISOString(),
}];

const ID_TO_NAME = {
  23757:"cell_voltage_min_v", 23758:"cell_voltage_max_v",
  23759:"cell_temp_min_c",    23760:"cell_temp_max_c",
  23761:"module_voltage_min_v",23762:"module_voltage_max_v",
  23763:"module_temp_max_c",  23764:"module_temp_min_c",
  23765:"soc_pct",            23766:"soe_kwh",
  23767:"dc_voltage_v",       23768:"dc_current_a",
  23769:"cell_id_max_temp",   23770:"cell_id_min_temp",
  23771:"module_id_max_temp", 23772:"module_id_min_temp",
  23773:"cell_id_max_voltage",23774:"cell_id_min_voltage",
  23775:"module_id_max_voltage",23776:"module_id_min_voltage",
};

const labels = input.labelsData;
const dict = input.dictData;

if (!Array.isArray(labels)) throw new Error("labelsData missing or not array");
if (!dict || typeof dict !== "object") throw new Error("dictData missing or not object");

function parseKey(key) {
  const m = /^el_(\d+)_(\w+)$/.exec(key);
  if (!m) return null;
  return { elementId: Number(m[1]), agg: m[2] };
}

// Prepare series descriptors once
const series = Object.keys(dict).map((k) => {
  const p = parseKey(k);
  const base = p ? (ID_TO_NAME[p.elementId] ?? `element_${p.elementId}`) : k;
  const col = p ? `${base}_${p.agg}` : k;
  const arr = Array.isArray(dict[k]) ? dict[k] : null;
  return { col, arr };
});

const rows = new Array(labels.length);

for (let i = 0; i < labels.length; i++) {
  const row = { time: new Date(labels[i]).toISOString() };
  for (let s = 0; s < series.length; s++) {
    const { col, arr } = series[s];
    row[col] = arr ? (arr[i] ?? null) : null;
  }
  rows[i] = row;
}

return rows;
